//! The normalized dictionary model and validation types.

use std::collections::{BTreeMap, BTreeSet};

use truefix_core::Field;

/// A FIX field's value type (drives format validation).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum FieldType {
    /// Integer.
    Int,
    /// Length.
    Length,
    /// Sequence number.
    SeqNum,
    /// Repeating-group count.
    NumInGroup,
    /// Float.
    Float,
    /// Price.
    Price,
    /// Quantity.
    Qty,
    /// Amount.
    Amt,
    /// Percentage.
    Percentage,
    /// Single character.
    Char,
    /// Boolean (`Y`/`N`).
    Boolean,
    /// String.
    String,
    /// Binary data.
    Data,
    /// UTC timestamp.
    UtcTimestamp,
    /// UTC time-only.
    UtcTimeOnly,
    /// UTC date-only.
    UtcDateOnly,
    /// Month-year.
    MonthYear,
}

impl FieldType {
    /// Parse a normalized type token (e.g. `"PRICE"`).
    pub fn parse(token: &str) -> Option<Self> {
        Some(match token {
            "INT" => Self::Int,
            "LENGTH" => Self::Length,
            "SEQNUM" => Self::SeqNum,
            "NUMINGROUP" => Self::NumInGroup,
            "FLOAT" => Self::Float,
            "PRICE" => Self::Price,
            "QTY" => Self::Qty,
            "AMT" => Self::Amt,
            "PERCENTAGE" => Self::Percentage,
            "CHAR" => Self::Char,
            "BOOLEAN" => Self::Boolean,
            "STRING" => Self::String,
            "DATA" => Self::Data,
            "UTCTIMESTAMP" => Self::UtcTimestamp,
            "UTCTIMEONLY" => Self::UtcTimeOnly,
            "UTCDATEONLY" => Self::UtcDateOnly,
            "MONTHYEAR" => Self::MonthYear,
            _ => return None,
        })
    }

    /// Whether `field`'s value is well-formed for this type.
    pub fn value_ok(self, field: &Field) -> bool {
        match self {
            Self::Int | Self::Length | Self::SeqNum | Self::NumInGroup => field.as_int().is_ok(),
            Self::Float | Self::Price | Self::Qty | Self::Amt | Self::Percentage => {
                field.as_decimal().is_ok()
            }
            Self::Char => field.as_char().is_ok(),
            Self::Boolean => field.as_bool().is_ok(),
            Self::UtcTimestamp => field.as_utc_timestamp().is_ok(),
            // String/Data/date/time-only are accepted as-is at this layer.
            _ => true,
        }
    }
}

/// A field definition.
#[derive(Debug, Clone)]
pub struct FieldDef {
    /// Tag number.
    pub tag: u32,
    /// Field name.
    pub name: String,
    /// Value type.
    pub field_type: FieldType,
    /// Allowed enumerated values (empty = any value of the type).
    pub values: Vec<String>,
}

impl FieldDef {
    /// Whether `value` is allowed (always true when the field is not enumerated).
    pub fn allows(&self, value: &str) -> bool {
        self.values.is_empty() || self.values.iter().any(|v| v == value)
    }
}

/// A message definition: required and optional field tags.
#[derive(Debug, Clone)]
pub struct MessageDef {
    /// MsgType value (e.g. `"D"`).
    pub msg_type: String,
    /// Message name (e.g. `"NewOrderSingle"`).
    pub name: String,
    /// Required body field tags.
    pub required: Vec<u32>,
    /// Optional body field tags.
    pub optional: Vec<u32>,
}

impl MessageDef {
    /// Whether `tag` is a defined body field of this message.
    pub fn allows_tag(&self, tag: u32) -> bool {
        self.required.contains(&tag) || self.optional.contains(&tag)
    }
}

/// A parsed FIX data dictionary for one version.
#[derive(Debug, Clone)]
pub struct DataDictionary {
    pub(crate) version: String,
    pub(crate) fields: BTreeMap<u32, FieldDef>,
    pub(crate) field_by_name: BTreeMap<String, u32>,
    pub(crate) messages: BTreeMap<String, MessageDef>,
    pub(crate) header: BTreeSet<u32>,
    pub(crate) trailer: BTreeSet<u32>,
    pub(crate) hash: u64,
}

impl DataDictionary {
    /// The dictionary version (BeginString).
    pub fn version(&self) -> &str {
        &self.version
    }

    /// The content hash of the source this dictionary was parsed from.
    pub fn hash(&self) -> u64 {
        self.hash
    }

    /// Look up a field definition by tag.
    pub fn field(&self, tag: u32) -> Option<&FieldDef> {
        self.fields.get(&tag)
    }

    /// Look up a field's tag by name.
    pub fn field_by_name(&self, name: &str) -> Option<u32> {
        self.field_by_name.get(name).copied()
    }

    /// Look up a message definition by MsgType.
    pub fn message(&self, msg_type: &str) -> Option<&MessageDef> {
        self.messages.get(msg_type)
    }

    /// Whether `tag` is a header field.
    pub fn is_header(&self, tag: u32) -> bool {
        self.header.contains(&tag)
    }

    /// Whether `tag` is a trailer field.
    pub fn is_trailer(&self, tag: u32) -> bool {
        self.trailer.contains(&tag)
    }

    /// Number of defined fields.
    pub fn field_count(&self) -> usize {
        self.fields.len()
    }

    /// Number of defined messages.
    pub fn message_count(&self) -> usize {
        self.messages.len()
    }
}

/// FIX SessionRejectReason / business reject reason for a validation failure.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum RejectReason {
    /// Tag number is not defined in the dictionary (0).
    InvalidTagNumber,
    /// A required tag is missing (1).
    RequiredTagMissing,
    /// Tag not defined for this message type (2).
    TagNotDefinedForMessageType,
    /// Undefined tag (3).
    UndefinedTag,
    /// Tag specified without a value (4).
    TagSpecifiedWithoutValue,
    /// Value is incorrect / out of range for the field (5).
    ValueIsIncorrect,
    /// Incorrect data format for the value (6).
    IncorrectDataFormat,
    /// Invalid or unsupported MsgType (11).
    InvalidMsgType,
}

impl RejectReason {
    /// The numeric SessionRejectReason (tag 373) code.
    pub fn code(self) -> u32 {
        match self {
            Self::InvalidTagNumber => 0,
            Self::RequiredTagMissing => 1,
            Self::TagNotDefinedForMessageType => 2,
            Self::UndefinedTag => 3,
            Self::TagSpecifiedWithoutValue => 4,
            Self::ValueIsIncorrect => 5,
            Self::IncorrectDataFormat => 6,
            Self::InvalidMsgType => 11,
        }
    }
}

/// A validation failure.
#[derive(Debug, Clone, PartialEq, Eq, thiserror::Error)]
#[error("{reason:?} (tag {ref_tag:?}): {text}")]
pub struct ValidationError {
    /// Why the message was rejected.
    pub reason: RejectReason,
    /// The offending tag, if applicable.
    pub ref_tag: Option<u32>,
    /// `true` => business-level reject; `false` => session-level reject.
    pub business: bool,
    /// Human-readable detail.
    pub text: String,
}

impl ValidationError {
    pub(crate) fn session(reason: RejectReason, ref_tag: Option<u32>, text: &str) -> Self {
        Self {
            reason,
            ref_tag,
            business: false,
            text: text.to_owned(),
        }
    }

    pub(crate) fn business(reason: RejectReason, ref_tag: Option<u32>, text: &str) -> Self {
        Self {
            reason,
            ref_tag,
            business: true,
            text: text.to_owned(),
        }
    }
}

/// Which validation checks to apply (maps to the FIX `Validate*` config toggles).
#[derive(Debug, Clone, Copy)]
pub struct ValidationOptions {
    /// Reject fields present with an empty value.
    pub validate_fields_have_values: bool,
    /// Validate user-defined fields (tags ≥ 5000) rather than skipping them.
    pub validate_user_defined_fields: bool,
    /// Permit fields not defined for the message type / dictionary.
    pub allow_unknown_msg_fields: bool,
    /// Check that required fields are present.
    pub check_required_fields: bool,
    /// Check field value formats and enumerations.
    pub check_field_types: bool,
}

impl Default for ValidationOptions {
    fn default() -> Self {
        Self {
            validate_fields_have_values: true,
            validate_user_defined_fields: false,
            allow_unknown_msg_fields: false,
            check_required_fields: true,
            check_field_types: true,
        }
    }
}

//! Parser for the normalized dictionary format.

use std::collections::{BTreeMap, BTreeSet};

use thiserror::Error;

use crate::hash::fnv1a;
use crate::model::{DataDictionary, FieldDef, FieldType, MessageDef};

/// An error parsing a normalized dictionary.
#[derive(Debug, Clone, PartialEq, Eq, Error)]
pub enum ParseError {
    /// No `version` directive was found.
    #[error("missing `version` directive")]
    MissingVersion,
    /// A line could not be parsed.
    #[error("line {line}: {reason}")]
    Malformed {
        /// 1-based line number.
        line: usize,
        /// Reason.
        reason: &'static str,
    },
    /// An unknown field type token.
    #[error("line {line}: unknown field type {token:?}")]
    UnknownType {
        /// 1-based line number.
        line: usize,
        /// The offending token.
        token: String,
    },
}

/// Parse a normalized dictionary document.
pub fn parse(input: &str) -> Result<DataDictionary, ParseError> {
    let mut version: Option<String> = None;
    let mut fields: BTreeMap<u32, FieldDef> = BTreeMap::new();
    let mut field_by_name: BTreeMap<String, u32> = BTreeMap::new();
    let mut messages: BTreeMap<String, MessageDef> = BTreeMap::new();
    let mut header: BTreeSet<u32> = BTreeSet::new();
    let mut trailer: BTreeSet<u32> = BTreeSet::new();

    for (idx, raw) in input.lines().enumerate() {
        let line_no = idx + 1;
        let line = strip_comment(raw).trim();
        if line.is_empty() {
            continue;
        }
        let mut tokens = line.split_whitespace();
        let directive = tokens.next().unwrap_or("");
        match directive {
            "version" => {
                let v = tokens.next().ok_or(ParseError::Malformed {
                    line: line_no,
                    reason: "version requires a value",
                })?;
                version = Some(v.to_owned());
            }
            "field" => {
                let tag = parse_tag(tokens.next(), line_no)?;
                let name = tokens.next().ok_or(ParseError::Malformed {
                    line: line_no,
                    reason: "field requires a name",
                })?;
                let type_token = tokens.next().ok_or(ParseError::Malformed {
                    line: line_no,
                    reason: "field requires a type",
                })?;
                let field_type =
                    FieldType::parse(type_token).ok_or_else(|| ParseError::UnknownType {
                        line: line_no,
                        token: type_token.to_owned(),
                    })?;
                let values: Vec<String> = tokens.map(str::to_owned).collect();
                fields.insert(
                    tag,
                    FieldDef {
                        tag,
                        name: name.to_owned(),
                        field_type,
                        values,
                    },
                );
                field_by_name.insert(name.to_owned(), tag);
            }
            "header" => {
                for t in tokens {
                    header.insert(parse_tag(Some(t), line_no)?);
                }
            }
            "trailer" => {
                for t in tokens {
                    trailer.insert(parse_tag(Some(t), line_no)?);
                }
            }
            "message" => {
                let msg_type = tokens.next().ok_or(ParseError::Malformed {
                    line: line_no,
                    reason: "message requires a MsgType",
                })?;
                let name = tokens.next().ok_or(ParseError::Malformed {
                    line: line_no,
                    reason: "message requires a name",
                })?;
                let mut required = Vec::new();
                let mut optional = Vec::new();
                for token in tokens {
                    if let Some(list) = token.strip_prefix("req:") {
                        required = parse_tag_list(list, line_no)?;
                    } else if let Some(list) = token.strip_prefix("opt:") {
                        optional = parse_tag_list(list, line_no)?;
                    }
                }
                messages.insert(
                    msg_type.to_owned(),
                    MessageDef {
                        msg_type: msg_type.to_owned(),
                        name: name.to_owned(),
                        required,
                        optional,
                    },
                );
            }
            _ => {
                return Err(ParseError::Malformed {
                    line: line_no,
                    reason: "unknown directive",
                })
            }
        }
    }

    let version = version.ok_or(ParseError::MissingVersion)?;
    Ok(DataDictionary {
        version,
        fields,
        field_by_name,
        messages,
        header,
        trailer,
        hash: fnv1a(input.as_bytes()),
    })
}

fn strip_comment(line: &str) -> &str {
    match line.find('#') {
        Some(idx) => line.get(..idx).unwrap_or(""),
        None => line,
    }
}

fn parse_tag(token: Option<&str>, line: usize) -> Result<u32, ParseError> {
    token
        .and_then(|t| t.parse().ok())
        .ok_or(ParseError::Malformed {
            line,
            reason: "expected a numeric tag",
        })
}

fn parse_tag_list(list: &str, line: usize) -> Result<Vec<u32>, ParseError> {
    list.split(',')
        .filter(|s| !s.is_empty())
        .map(|s| {
            s.parse().map_err(|_| ParseError::Malformed {
                line,
                reason: "expected a comma-separated tag list",
            })
        })
        .collect()
}

//! Runtime message validation against a [`DataDictionary`].

use truefix_core::Message;

use crate::model::{DataDictionary, RejectReason, ValidationError, ValidationOptions};

/// The first user-defined-field tag (UDFs occupy 5000–9999 in FIX).
const UDF_START: u32 = 5000;

impl DataDictionary {
    /// Validate `message` against this dictionary using `opts`.
    ///
    /// Returns the first failure found. Field-membership/format/required failures are
    /// session-level rejects; an unknown-but-structural MsgType is a business-level reject
    /// (FR-C4 two rejection layers).
    pub fn validate(
        &self,
        message: &Message,
        opts: &ValidationOptions,
    ) -> Result<(), ValidationError> {
        let msg_type = message.msg_type().ok_or_else(|| {
            ValidationError::session(RejectReason::InvalidMsgType, Some(35), "missing MsgType")
        })?;
        let mdef = self.message(msg_type).ok_or_else(|| {
            ValidationError::business(
                RejectReason::InvalidMsgType,
                Some(35),
                "MsgType not defined in dictionary",
            )
        })?;

        for field in message
            .header
            .fields()
            .chain(message.body.fields())
            .chain(message.trailer.fields())
        {
            let tag = field.tag();

            if opts.validate_fields_have_values && field.value_bytes().is_empty() {
                return Err(ValidationError::session(
                    RejectReason::TagSpecifiedWithoutValue,
                    Some(tag),
                    "field has no value",
                ));
            }

            match self.field(tag) {
                None => {
                    let is_udf = tag >= UDF_START;
                    if is_udf && !opts.validate_user_defined_fields {
                        continue;
                    }
                    if opts.allow_unknown_msg_fields {
                        continue;
                    }
                    return Err(ValidationError::session(
                        RejectReason::InvalidTagNumber,
                        Some(tag),
                        "tag not defined in dictionary",
                    ));
                }
                Some(fdef) => {
                    if opts.check_field_types {
                        if !fdef.field_type.value_ok(field) {
                            return Err(ValidationError::session(
                                RejectReason::IncorrectDataFormat,
                                Some(tag),
                                "value has incorrect data format",
                            ));
                        }
                        if let Ok(value) = field.as_str() {
                            if !fdef.allows(value) {
                                return Err(ValidationError::session(
                                    RejectReason::ValueIsIncorrect,
                                    Some(tag),
                                    "value is not an allowed enumeration",
                                ));
                            }
                        }
                    }

                    let belongs =
                        self.is_header(tag) || self.is_trailer(tag) || mdef.allows_tag(tag);
                    if !belongs && !opts.allow_unknown_msg_fields {
                        return Err(ValidationError::session(
                            RejectReason::TagNotDefinedForMessageType,
                            Some(tag),
                            "tag not defined for this message type",
                        ));
                    }
                }
            }
        }

        if opts.check_required_fields {
            for &tag in &mdef.required {
                if !present(message, tag) {
                    return Err(ValidationError::session(
                        RejectReason::RequiredTagMissing,
                        Some(tag),
                        "required field missing",
                    ));
                }
            }
        }

        Ok(())
    }
}

fn present(message: &Message, tag: u32) -> bool {
    message.header.get(tag).is_some()
        || message.body.get(tag).is_some()
        || message.trailer.get(tag).is_some()
}

//! FIXT 1.1 transport/application dictionary separation.
//!
//! Under FIXT 1.1 the session (transport) layer and the application layer use **separate**
//! dictionaries. The application dictionary is selected per-message by ApplVerID, falling back to
//! the session's DefaultApplVerID.

use std::collections::BTreeMap;

use crate::model::DataDictionary;

/// A transport dictionary plus one or more application dictionaries keyed by application version.
#[derive(Debug, Clone)]
pub struct FixtDictionaries {
    transport: DataDictionary,
    applications: BTreeMap<String, DataDictionary>,
    default_appl_ver_id: Option<String>,
}

impl FixtDictionaries {
    /// Create from a transport dictionary; add application dictionaries with
    /// [`with_application`](Self::with_application).
    pub fn new(transport: DataDictionary) -> Self {
        Self {
            transport,
            applications: BTreeMap::new(),
            default_appl_ver_id: None,
        }
    }

    /// Register an application dictionary under an application version id (e.g. `"FIX.5.0"`).
    pub fn with_application(
        mut self,
        appl_ver_id: impl Into<String>,
        dict: DataDictionary,
    ) -> Self {
        self.applications.insert(appl_ver_id.into(), dict);
        self
    }

    /// Set the DefaultApplVerID used when a message does not carry an explicit ApplVerID.
    pub fn with_default_appl_ver_id(mut self, appl_ver_id: impl Into<String>) -> Self {
        self.default_appl_ver_id = Some(appl_ver_id.into());
        self
    }

    /// The transport (session-layer) dictionary.
    pub fn transport(&self) -> &DataDictionary {
        &self.transport
    }

    /// Resolve the application dictionary for an explicit `appl_ver_id`, falling back to the
    /// DefaultApplVerID.
    pub fn application_for(&self, appl_ver_id: Option<&str>) -> Option<&DataDictionary> {
        let key = appl_ver_id.or(self.default_appl_ver_id.as_deref())?;
        self.applications.get(key)
    }
}

//! Stable content hash (FNV-1a, 64-bit) used to prove the codegen track and the runtime track
//! derive from the same dictionary source (Constitution Principle IV). The identical algorithm is
//! duplicated in `build.rs`.

pub(crate) fn fnv1a(bytes: &[u8]) -> u64 {
    let mut hash: u64 = 0xcbf2_9ce4_8422_2325;
    for &b in bytes {
        hash ^= u64::from(b);
        hash = hash.wrapping_mul(0x0000_0100_0000_01b3);
    }
    hash
}

//! Build-time codegen (dual-track, Constitution Principle IV).
//!
//! Reads the same normalized dictionary sources the runtime loads, and generates per-version
//! message-type constants plus a content hash. The runtime asserts its parsed hash equals the
//! generated one, proving codegen and runtime derive from one source.

use std::env;
use std::fmt::Write as _;
use std::fs;
use std::path::Path;

fn fnv1a(bytes: &[u8]) -> u64 {
    let mut hash: u64 = 0xcbf2_9ce4_8422_2325;
    for &b in bytes {
        hash ^= u64::from(b);
        hash = hash.wrapping_mul(0x0000_0100_0000_01b3);
    }
    hash
}

fn main() {
    let manifest = env::var("CARGO_MANIFEST_DIR").expect("CARGO_MANIFEST_DIR");
    let out_dir = env::var("OUT_DIR").expect("OUT_DIR");
    let mut code = String::new();
    code.push_str("// @generated by build.rs from dict-src/normalized — do not edit.\n");

    for (name, file) in [
        ("FIX40", "FIX40.fixdict"),
        ("FIX41", "FIX41.fixdict"),
        ("FIX42", "FIX42.fixdict"),
        ("FIX43", "FIX43.fixdict"),
        ("FIX44", "FIX44.fixdict"),
        ("FIXT11", "FIXT11.fixdict"),
        ("FIX50", "FIX50.fixdict"),
        ("FIX50SP1", "FIX50SP1.fixdict"),
        ("FIX50SP2", "FIX50SP2.fixdict"),
    ] {
        let path = Path::new(&manifest).join("dict-src/normalized").join(file);
        println!("cargo:rerun-if-changed={}", path.display());
        let bytes = fs::read(&path).unwrap_or_else(|e| panic!("read {}: {e}", path.display()));
        let hash = fnv1a(&bytes);
        let _ = writeln!(code, "/// Content hash of the {name} dictionary source.");
        let _ = writeln!(code, "pub const {name}_DICT_HASH: u64 = {hash};");

        let module = name.to_lowercase();
        let _ = writeln!(
            code,
            "/// Generated MsgType constants for the {name} dictionary."
        );
        let _ = writeln!(code, "pub mod {module}_msgs {{");
        for line in String::from_utf8_lossy(&bytes).lines() {
            let line = line.trim();
            if let Some(rest) = line.strip_prefix("message ") {
                let mut it = rest.split_whitespace();
                if let (Some(msg_type), Some(msg_name)) = (it.next(), it.next()) {
                    let ident = msg_name.to_uppercase();
                    let _ = writeln!(code, "    /// MsgType for {msg_name}.");
                    let _ = writeln!(code, "    pub const {ident}: &str = {msg_type:?};");
                }
            }
        }
        let _ = writeln!(code, "}}");
    }

    let dest = Path::new(&out_dir).join("generated.rs");
    fs::write(&dest, code).unwrap_or_else(|e| panic!("write generated.rs: {e}"));
}

//! `truefix-session` — the FIX session layer.
//!
//! Stage S2 provides the sans-IO [`Session`] state machine (logon/heartbeat/test-request/
//! logout), the [`Application`] callback trait, [`SessionId`], and [`SessionConfig`].
//! Sequence-gap recovery, persistence, scheduling, and the remaining session semantics arrive
//! in later stages.
//!
//! Design: `specs/001-fix-engine-parity/`.
#![cfg_attr(
    not(test),
    deny(
        clippy::unwrap_used,
        clippy::expect_used,
        clippy::panic,
        clippy::indexing_slicing
    )
)]

mod admin;
pub mod application;
pub mod config;
pub mod schedule;
pub mod session_id;
pub mod state;
mod tags;
mod time_util;

pub use application::Application;
pub use config::{Role, SessionConfig};
pub use schedule::Schedule;
pub use session_id::SessionId;
pub use state::{Action, Event, Session, SessionState, SessionStatus};

//! The sans-IO session state machine.
//!
//! The engine consumes [`Event`]s and returns [`Action`]s, performing no I/O itself, so it is
//! deterministic and unit-testable; the transport drives it. Stage S3 adds inbound sequence
//! validation, an in-memory store of sent messages, ResendRequest/SequenceReset handling
//! (gap fill, PossDup/OrigSendingTime), chunked resend, ResetSeqNumFlag, and NextExpectedMsgSeqNum.
//! Persistence beyond memory and scheduling arrive in later stages.

use core::cmp::Ordering;
use std::collections::BTreeMap;

use truefix_core::{Field, Message};
use truefix_dict::{DataDictionary, ValidationOptions};

use crate::admin;
use crate::config::{Role, SessionConfig};
use crate::session_id::SessionId;
use crate::tags::{
    GAP_FILL_FLAG, HEART_BT_INT, MSG_SEQ_NUM, NEW_SEQ_NO, POSS_DUP_FLAG, RESET_SEQ_NUM_FLAG,
};
use crate::time_util::now_utc_timestamp;

/// Session lifecycle state.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum SessionState {
    /// Not connected / logged out.
    Disconnected,
    /// Logon sent or awaited; not yet logged on.
    AwaitingLogon,
    /// Fully logged on.
    LoggedOn,
    /// Logout initiated; awaiting the counterparty's Logout.
    AwaitingLogout,
}

/// An input to the engine.
#[derive(Debug)]
pub enum Event {
    /// The transport connection is established.
    Connected,
    /// An inbound message was decoded.
    Received(Message),
    /// A periodic (≈1 second) timer tick.
    Tick,
    /// The application requested a graceful logout.
    StartLogout,
}

/// A point-in-time snapshot of a session, for monitoring (FR-L1).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct SessionStatus {
    /// Lifecycle state.
    pub state: SessionState,
    /// Whether the session is logged on.
    pub logged_on: bool,
    /// Next outbound sequence number.
    pub next_sender_seq: u64,
    /// Next inbound sequence number expected.
    pub next_target_seq: u64,
}

/// An output from the engine for the transport to perform.
#[derive(Debug)]
pub enum Action {
    /// Send this message to the counterparty.
    Send(Message),
    /// Close the connection.
    Disconnect,
}

/// A single FIX session.
pub struct Session {
    config: SessionConfig,
    id: SessionId,
    state: SessionState,
    next_out_seq: u64,
    next_in_seq: u64,
    ticks_since_send: u32,
    ticks_since_recv: u32,
    ticks_awaiting: u32,
    test_request_outstanding: bool,
    logon_sent: bool,
    resend_requested: bool,
    /// Sent messages, by sequence number, for resend.
    store: BTreeMap<u64, Message>,
    /// Received out-of-order messages (seq > expected), awaiting gap fill.
    queue: BTreeMap<u64, Message>,
    /// Optional inbound application-message validator (dictionary + toggles).
    validator: Option<(DataDictionary, ValidationOptions)>,
}

impl Session {
    /// Create a new session in the `Disconnected` state.
    pub fn new(config: SessionConfig) -> Self {
        let id = config.session_id();
        Self {
            config,
            id,
            state: SessionState::Disconnected,
            next_out_seq: 1,
            next_in_seq: 1,
            ticks_since_send: 0,
            ticks_since_recv: 0,
            ticks_awaiting: 0,
            test_request_outstanding: false,
            logon_sent: false,
            resend_requested: false,
            store: BTreeMap::new(),
            queue: BTreeMap::new(),
            validator: None,
        }
    }

    /// Enable inbound application-message validation against `dict` using `opts`. Admin messages
    /// are not validated here. Invalid messages produce a Reject (session-level) or
    /// BusinessMessageReject (business-level) instead of being delivered.
    pub fn set_dictionary(&mut self, dict: DataDictionary, opts: ValidationOptions) {
        self.validator = Some((dict, opts));
    }

    /// The session's identity.
    pub fn id(&self) -> &SessionId {
        &self.id
    }

    /// The current state.
    pub fn state(&self) -> SessionState {
        self.state
    }

    /// Whether the session is logged on.
    pub fn is_logged_on(&self) -> bool {
        self.state == SessionState::LoggedOn
    }

    /// The next outbound sequence number that will be used.
    pub fn next_out_seq(&self) -> u64 {
        self.next_out_seq
    }

    /// The next inbound sequence number expected.
    pub fn next_in_seq(&self) -> u64 {
        self.next_in_seq
    }

    /// Seed the sequence numbers from a persistent store (call before [`Event::Connected`]).
    /// Has no effect once a logon has been sent.
    pub fn seed_sequences(&mut self, next_out: u64, next_in: u64) {
        if !self.logon_sent {
            self.next_out_seq = next_out.max(1);
            self.next_in_seq = next_in.max(1);
        }
    }

    /// A monitoring snapshot of the session (FR-L1).
    pub fn status(&self) -> SessionStatus {
        SessionStatus {
            state: self.state,
            logged_on: self.is_logged_on(),
            next_sender_seq: self.next_out_seq,
            next_target_seq: self.next_in_seq,
        }
    }

    /// Operational reset: clear stored messages and set both sequence numbers back to 1 (FR-L2).
    pub fn reset(&mut self) {
        self.reset_sequences(true);
        self.logon_sent = false;
    }

    /// Drive the engine with an [`Event`], producing [`Action`]s.
    pub fn handle(&mut self, event: Event) -> Vec<Action> {
        match event {
            Event::Connected => self.on_connected(),
            Event::Received(msg) => self.on_received(msg),
            Event::Tick => self.on_tick(),
            Event::StartLogout => self.on_start_logout(),
        }
    }

    /// Send an application message: stamps the header (seq, comp IDs, SendingTime), stores it for
    /// possible resend, and returns the send action.
    pub fn send_app(&mut self, mut msg: Message) -> Vec<Action> {
        let seq = self.next_seq();
        msg.header.set(Field::string(8, &self.config.begin_string));
        msg.header
            .set(Field::string(49, &self.config.sender_comp_id));
        msg.header
            .set(Field::string(56, &self.config.target_comp_id));
        msg.header.set(Field::int(MSG_SEQ_NUM, seq as i64));
        msg.header.set(Field::string(52, &now_utc_timestamp()));
        vec![self.send_stored(msg)]
    }

    fn hb(&self) -> u32 {
        self.config.heartbeat_interval.max(1)
    }

    fn next_seq(&mut self) -> u64 {
        let s = self.next_out_seq;
        self.next_out_seq = self.next_out_seq.saturating_add(1);
        s
    }

    /// Send a normally-sequenced message: store it by its MsgSeqNum for resend, reset the send
    /// timer.
    fn send_stored(&mut self, msg: Message) -> Action {
        self.ticks_since_send = 0;
        if let Some(seq) = msg
            .header
            .get(MSG_SEQ_NUM)
            .and_then(|f| f.as_int().ok())
            .filter(|&s| s > 0)
        {
            self.store.insert(seq as u64, msg.clone());
        }
        Action::Send(msg)
    }

    /// Send without allocating a new sequence number or storing (used for resend responses).
    fn send_raw(&mut self, msg: Message) -> Action {
        self.ticks_since_send = 0;
        Action::Send(msg)
    }

    fn reset_sequences(&mut self, full: bool) {
        self.next_in_seq = 1;
        self.queue.clear();
        self.resend_requested = false;
        if full {
            self.next_out_seq = 1;
            self.store.clear();
        }
    }

    fn latency_ok(&self, msg: &Message) -> bool {
        if !self.config.check_latency {
            return true;
        }
        let Some(field) = msg.header.get(crate::tags::SENDING_TIME) else {
            return true;
        };
        let Ok(ts) = field.as_utc_timestamp() else {
            return true; // unparseable SendingTime is a dictionary/validation concern
        };
        let now = time::OffsetDateTime::now_utc();
        (now - ts).whole_seconds().abs() <= i64::from(self.config.max_latency)
    }

    fn on_connected(&mut self) -> Vec<Action> {
        self.ticks_awaiting = 0;
        self.state = SessionState::AwaitingLogon;
        match self.config.role {
            Role::Initiator => {
                let next_exp = self.maybe_next_expected();
                let seq = self.next_seq();
                let msg = admin::logon(&self.config, seq, next_exp);
                self.logon_sent = true;
                vec![self.send_stored(msg)]
            }
            Role::Acceptor => Vec::new(),
        }
    }

    fn maybe_next_expected(&self) -> Option<u64> {
        if self.config.enable_next_expected_msg_seq_num {
            Some(self.next_in_seq)
        } else {
            None
        }
    }

    fn on_received(&mut self, msg: Message) -> Vec<Action> {
        self.ticks_since_recv = 0;
        self.test_request_outstanding = false;

        // CheckLatency / MaxLatency: a stale SendingTime aborts the session.
        if !self.latency_ok(&msg) {
            let seq = self.next_seq();
            let lo = admin::logout(&self.config, seq, Some("SendingTime accuracy problem"));
            self.state = SessionState::Disconnected;
            return vec![self.send_stored(lo), Action::Disconnect];
        }

        let mt = msg.msg_type().map(str::to_owned);

        if mt.as_deref() == Some("A") {
            return self.on_logon(msg);
        }
        if mt.as_deref() == Some("4") {
            return self.on_sequence_reset(&msg);
        }

        let seq = match msg
            .header
            .get(MSG_SEQ_NUM)
            .and_then(|f| f.as_int().ok())
            .filter(|&s| s > 0)
        {
            Some(s) => s as u64,
            None => {
                let s = self.next_seq();
                let rej = admin::reject(&self.config, s, 0, "missing or invalid MsgSeqNum");
                return vec![self.send_stored(rej)];
            }
        };
        let poss_dup = msg.header.get(POSS_DUP_FLAG).and_then(|f| f.as_str().ok()) == Some("Y");

        match seq.cmp(&self.next_in_seq) {
            Ordering::Equal => {
                if let Some(reject) = self.validate_app(&msg) {
                    let mut actions = vec![reject];
                    self.next_in_seq = self.next_in_seq.saturating_add(1);
                    actions.extend(self.drain_queue());
                    return actions;
                }
                let mut actions = self.process_in_order(&msg, mt.as_deref());
                self.next_in_seq = self.next_in_seq.saturating_add(1);
                actions.extend(self.drain_queue());
                actions
            }
            Ordering::Greater => {
                self.queue.insert(seq, msg);
                if self.resend_requested {
                    Vec::new()
                } else {
                    self.resend_requested = true;
                    let begin = self.next_in_seq;
                    vec![self.request_resend(begin)]
                }
            }
            Ordering::Less => {
                if poss_dup {
                    Vec::new()
                } else {
                    let s = self.next_seq();
                    let lo = admin::logout(&self.config, s, Some("MsgSeqNum too low"));
                    self.state = SessionState::Disconnected;
                    vec![self.send_stored(lo), Action::Disconnect]
                }
            }
        }
    }

    /// Validate an inbound application message; on failure, return a Reject/BusinessMessageReject
    /// action. Admin messages and the no-dictionary case return `None`.
    fn validate_app(&mut self, msg: &Message) -> Option<Action> {
        let error = {
            let (dict, opts) = self.validator.as_ref()?;
            if is_admin_type(msg.msg_type()) {
                return None;
            }
            dict.validate(msg, opts).err()
        }?;
        let ref_seq = msg
            .header
            .get(MSG_SEQ_NUM)
            .and_then(|f| f.as_int().ok())
            .filter(|&s| s > 0)
            .map_or(0, |s| s as u64);
        let ref_mt = msg.msg_type().map(str::to_owned);
        let seq = self.next_seq();
        let reject = if error.business {
            admin::business_message_reject(
                &self.config,
                seq,
                ref_seq,
                ref_mt.as_deref(),
                error.reason.code(),
                &error.text,
            )
        } else {
            admin::reject_with_reason(&self.config, seq, ref_seq, error.reason.code(), &error.text)
        };
        Some(self.send_stored(reject))
    }

    fn process_in_order(&mut self, msg: &Message, mt: Option<&str>) -> Vec<Action> {
        match mt {
            Some("1") => self.answer_test_request(msg),
            Some("2") => self.on_resend_request(msg),
            Some("5") => self.on_logout_msg(),
            _ => Vec::new(),
        }
    }

    fn drain_queue(&mut self) -> Vec<Action> {
        let mut actions = Vec::new();
        while let Some(msg) = self.queue.remove(&self.next_in_seq) {
            let mt = msg.msg_type().map(str::to_owned);
            actions.extend(self.process_in_order(&msg, mt.as_deref()));
            self.next_in_seq = self.next_in_seq.saturating_add(1);
        }
        if self.queue.is_empty() {
            self.resend_requested = false;
        }
        actions
    }

    fn request_resend(&mut self, begin: u64) -> Action {
        let chunk = u64::from(self.config.resend_request_chunk_size);
        let end = if chunk > 0 {
            begin + chunk - 1
        } else {
            0 // 0 = to infinity
        };
        let seq = self.next_seq();
        let rr = admin::resend_request(&self.config, seq, begin, end);
        self.send_stored(rr)
    }

    fn on_resend_request(&mut self, msg: &Message) -> Vec<Action> {
        let begin = msg
            .body
            .get(crate::tags::BEGIN_SEQ_NO)
            .and_then(|f| f.as_int().ok())
            .filter(|&s| s > 0)
            .map_or(0, |s| s as u64);
        let end_req = msg
            .body
            .get(crate::tags::END_SEQ_NO)
            .and_then(|f| f.as_int().ok())
            .filter(|&s| s >= 0)
            .map_or(0, |s| s as u64);
        let last = self.next_out_seq.saturating_sub(1);
        let end = if end_req == 0 || end_req > last {
            last
        } else {
            end_req
        };
        if begin == 0 || begin > end {
            return Vec::new();
        }
        self.build_resend(begin, end)
    }

    fn build_resend(&mut self, begin: u64, end: u64) -> Vec<Action> {
        let mut actions = Vec::new();
        let mut gap_start: Option<u64> = None;
        let mut seq = begin;
        while seq <= end {
            let stored = self.store.get(&seq).cloned();
            let is_app = stored
                .as_ref()
                .is_some_and(|m| !is_admin_type(m.msg_type()));
            if is_app {
                if let Some(gs) = gap_start.take() {
                    let action = self.gap_fill(gs, seq);
                    actions.push(action);
                }
                if let Some(m) = stored {
                    let resent = admin::prepare_resend(&m);
                    actions.push(self.send_raw(resent));
                }
            } else if gap_start.is_none() {
                gap_start = Some(seq);
            }
            seq = seq.saturating_add(1);
        }
        if let Some(gs) = gap_start.take() {
            let new_seq = end.saturating_add(1);
            let action = self.gap_fill(gs, new_seq);
            actions.push(action);
        }
        actions
    }

    fn gap_fill(&mut self, from_seq: u64, new_seq_no: u64) -> Action {
        let m = admin::sequence_reset(&self.config, from_seq, new_seq_no, true);
        self.send_raw(m)
    }

    fn on_sequence_reset(&mut self, msg: &Message) -> Vec<Action> {
        let gap_fill = msg.body.get(GAP_FILL_FLAG).and_then(|f| f.as_str().ok()) == Some("Y");
        let new_seq = msg
            .body
            .get(NEW_SEQ_NO)
            .and_then(|f| f.as_int().ok())
            .filter(|&n| n > 0)
            .map(|n| n as u64);
        if let Some(ns) = new_seq {
            if gap_fill {
                if ns >= self.next_in_seq {
                    self.next_in_seq = ns;
                }
            } else {
                self.next_in_seq = ns;
            }
        }
        self.drain_queue()
    }

    fn on_logon(&mut self, msg: Message) -> Vec<Action> {
        if msg
            .body
            .get(RESET_SEQ_NUM_FLAG)
            .and_then(|f| f.as_str().ok())
            == Some("Y")
        {
            self.reset_sequences(!self.logon_sent);
        }

        let mut actions = Vec::new();
        match self.config.role {
            Role::Acceptor if self.state == SessionState::AwaitingLogon => {
                if let Some(hbi) = msg
                    .body
                    .get(HEART_BT_INT)
                    .and_then(|f| f.as_int().ok())
                    .filter(|&h| h > 0)
                {
                    self.config.heartbeat_interval = hbi as u32;
                }
                self.state = SessionState::LoggedOn;
                let next_exp = self.maybe_next_expected();
                let seq = self.next_seq();
                let resp = admin::logon(&self.config, seq, next_exp);
                self.logon_sent = true;
                actions.push(self.send_stored(resp));
            }
            Role::Initiator if self.state == SessionState::AwaitingLogon => {
                self.state = SessionState::LoggedOn;
            }
            _ => {}
        }

        // Sequence accounting for the Logon message itself.
        if let Some(seq) = msg
            .header
            .get(MSG_SEQ_NUM)
            .and_then(|f| f.as_int().ok())
            .filter(|&s| s > 0)
            .map(|s| s as u64)
        {
            match seq.cmp(&self.next_in_seq) {
                Ordering::Equal => {
                    self.next_in_seq = self.next_in_seq.saturating_add(1);
                    actions.extend(self.drain_queue());
                }
                Ordering::Greater => {
                    if !self.resend_requested {
                        self.resend_requested = true;
                        let begin = self.next_in_seq;
                        actions.push(self.request_resend(begin));
                    }
                }
                Ordering::Less => {}
            }
        }
        actions
    }

    fn answer_test_request(&mut self, msg: &Message) -> Vec<Action> {
        if self.state != SessionState::LoggedOn {
            return Vec::new();
        }
        let id = msg
            .body
            .get(crate::tags::TEST_REQ_ID)
            .and_then(|f| f.as_str().ok())
            .map(str::to_owned);
        let seq = self.next_seq();
        let hb = admin::heartbeat(&self.config, seq, id.as_deref());
        vec![self.send_stored(hb)]
    }

    fn on_logout_msg(&mut self) -> Vec<Action> {
        if self.state == SessionState::AwaitingLogout {
            self.enter_disconnected();
            vec![Action::Disconnect]
        } else {
            let seq = self.next_seq();
            let lo = admin::logout(&self.config, seq, None);
            let send = self.send_stored(lo);
            self.enter_disconnected();
            vec![send, Action::Disconnect]
        }
    }

    fn on_start_logout(&mut self) -> Vec<Action> {
        if self.state == SessionState::LoggedOn {
            let seq = self.next_seq();
            let lo = admin::logout(&self.config, seq, None);
            self.ticks_awaiting = 0;
            self.state = SessionState::AwaitingLogout;
            vec![self.send_stored(lo)]
        } else {
            Vec::new()
        }
    }

    fn enter_disconnected(&mut self) {
        self.state = SessionState::Disconnected;
        if self.config.reset_on_disconnect || self.config.reset_on_logout {
            self.reset_sequences(true);
            self.logon_sent = false;
        }
    }

    fn on_tick(&mut self) -> Vec<Action> {
        self.ticks_since_send = self.ticks_since_send.saturating_add(1);
        self.ticks_since_recv = self.ticks_since_recv.saturating_add(1);
        self.ticks_awaiting = self.ticks_awaiting.saturating_add(1);
        let hb = self.hb();
        let mut actions = Vec::new();
        match self.state {
            SessionState::AwaitingLogon
                if self.ticks_awaiting >= self.config.logon_timeout.max(1) =>
            {
                self.enter_disconnected();
                return vec![Action::Disconnect];
            }
            SessionState::LoggedOn => {
                if self.ticks_since_recv >= 2 * hb + 2 {
                    self.enter_disconnected();
                    return vec![Action::Disconnect];
                }
                if self.ticks_since_recv > hb && !self.test_request_outstanding {
                    let seq = self.next_seq();
                    let tr = admin::test_request(&self.config, seq, "TEST");
                    self.test_request_outstanding = true;
                    actions.push(self.send_stored(tr));
                }
                if self.ticks_since_send >= hb {
                    let seq = self.next_seq();
                    let h = admin::heartbeat(&self.config, seq, None);
                    actions.push(self.send_stored(h));
                }
            }
            SessionState::AwaitingLogout
                if self.ticks_awaiting >= self.config.logout_timeout.max(1) =>
            {
                self.enter_disconnected();
                return vec![Action::Disconnect];
            }
            _ => {}
        }
        actions
    }
}

fn is_admin_type(mt: Option<&str>) -> bool {
    matches!(mt, Some("0" | "1" | "2" | "3" | "4" | "5" | "A"))
}

//! Session configuration (programmatic; the `.cfg` mapping lives in `truefix-config`).

use crate::session_id::SessionId;

/// Whether this side initiates (connects out) or accepts (listens).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Role {
    /// Buy-side / connects out.
    Initiator,
    /// Sell-side / listens.
    Acceptor,
}

/// Minimal session configuration needed for the S2 logon/heartbeat/logout flow.
///
/// Sequence recovery, persistence, scheduling, and the full Appendix A key surface arrive in
/// later stages; this is the bootstrap subset.
#[derive(Debug, Clone)]
pub struct SessionConfig {
    /// BeginString, e.g. `"FIX.4.4"`.
    pub begin_string: String,
    /// This engine's SenderCompID.
    pub sender_comp_id: String,
    /// The counterparty's TargetCompID.
    pub target_comp_id: String,
    /// Heartbeat interval in seconds (HeartBtInt, tag 108).
    pub heartbeat_interval: u32,
    /// Initiator or acceptor.
    pub role: Role,
    /// Whether to set ResetSeqNumFlag (141=Y) on the logon (resets both sequence numbers to 1).
    pub reset_on_logon: bool,
    /// Whether to reset sequence numbers on logout.
    pub reset_on_logout: bool,
    /// Whether to reset sequence numbers on disconnect.
    pub reset_on_disconnect: bool,
    /// Whether to refresh state from the store on logon.
    pub refresh_on_logon: bool,
    /// ResendRequest chunk size; `0` means request the whole range at once.
    pub resend_request_chunk_size: u32,
    /// Whether to use NextExpectedMsgSeqNum (789) on logon (FIX ≥ 4.4).
    pub enable_next_expected_msg_seq_num: bool,
    /// Whether to validate inbound SendingTime against the local clock.
    pub check_latency: bool,
    /// Maximum tolerated SendingTime latency, in seconds.
    pub max_latency: u32,
    /// Seconds to wait for the Logon handshake before giving up (LogonTimeout).
    pub logon_timeout: u32,
    /// Seconds to wait for the counterparty Logout before disconnecting (LogoutTimeout).
    pub logout_timeout: u32,
    /// Initiator reconnect interval, in seconds (ReconnectInterval).
    pub reconnect_interval: u32,
    /// Optional activity schedule (StartTime/EndTime/Weekdays/NonStop).
    pub schedule: Option<crate::schedule::Schedule>,
}

impl SessionConfig {
    /// Convenience constructor.
    pub fn new(
        begin_string: impl Into<String>,
        sender_comp_id: impl Into<String>,
        target_comp_id: impl Into<String>,
        role: Role,
    ) -> Self {
        Self {
            begin_string: begin_string.into(),
            sender_comp_id: sender_comp_id.into(),
            target_comp_id: target_comp_id.into(),
            heartbeat_interval: 30,
            role,
            reset_on_logon: true,
            reset_on_logout: false,
            reset_on_disconnect: false,
            refresh_on_logon: false,
            resend_request_chunk_size: 0,
            enable_next_expected_msg_seq_num: false,
            check_latency: true,
            max_latency: 120,
            logon_timeout: 10,
            logout_timeout: 10,
            reconnect_interval: 5,
            schedule: None,
        }
    }

    /// The [`SessionId`] this configuration describes.
    pub fn session_id(&self) -> SessionId {
        SessionId::new(
            self.begin_string.clone(),
            self.sender_comp_id.clone(),
            self.target_comp_id.clone(),
        )
    }
}

//! Session scheduling: when a session should be active.
//!
//! Supports 24×7 (NonStopSession), daily windows (StartTime/EndTime), a weekday filter, and a
//! fixed UTC offset (TimeZone, simplified to a whole-second offset). Named time zones and full
//! weekly StartDay/EndDay windows can extend this later.

use time::{OffsetDateTime, Time, UtcOffset, Weekday};

/// A session activity schedule.
#[derive(Debug, Clone, Default)]
pub struct Schedule {
    /// Always in session (24×7).
    pub non_stop: bool,
    /// Daily window start (local time), if any.
    pub start_time: Option<Time>,
    /// Daily window end (local time), if any.
    pub end_time: Option<Time>,
    /// Allowed weekdays; `None` means every day.
    pub weekdays: Option<Vec<Weekday>>,
    /// Local time-zone offset from UTC, in whole seconds.
    pub utc_offset_seconds: i32,
}

impl Schedule {
    /// A 24×7 schedule.
    pub fn non_stop() -> Self {
        Self {
            non_stop: true,
            ..Self::default()
        }
    }

    /// A daily window `[start, end)` in local time (wraps past midnight if `end < start`).
    pub fn daily(start: Time, end: Time) -> Self {
        Self {
            start_time: Some(start),
            end_time: Some(end),
            ..Self::default()
        }
    }

    /// Restrict to the given weekdays.
    pub fn with_weekdays(mut self, days: Vec<Weekday>) -> Self {
        self.weekdays = Some(days);
        self
    }

    /// Set the local UTC offset in whole seconds.
    pub fn with_utc_offset_seconds(mut self, seconds: i32) -> Self {
        self.utc_offset_seconds = seconds;
        self
    }

    /// Whether `now_utc` falls within the schedule.
    pub fn is_in_session(&self, now_utc: OffsetDateTime) -> bool {
        if self.non_stop {
            return true;
        }
        let offset =
            UtcOffset::from_whole_seconds(self.utc_offset_seconds).unwrap_or(UtcOffset::UTC);
        let local = now_utc.to_offset(offset);
        if let Some(days) = &self.weekdays {
            if !days.contains(&local.weekday()) {
                return false;
            }
        }
        match (self.start_time, self.end_time) {
            (Some(start), Some(end)) => in_window(local.time(), start, end),
            _ => true,
        }
    }
}

fn in_window(t: Time, start: Time, end: Time) -> bool {
    if start <= end {
        t >= start && t < end
    } else {
        // window wraps past midnight
        t >= start || t < end
    }
}

//! Builders for session-level admin messages.

use truefix_core::{Field, Message};

use crate::config::SessionConfig;
use crate::tags::{
    BEGIN_SEQ_NO, BUSINESS_REJECT_REASON, ENCRYPT_METHOD, END_SEQ_NO, GAP_FILL_FLAG, HEART_BT_INT,
    NEW_SEQ_NO, NEXT_EXPECTED_MSG_SEQ_NUM, ORIG_SENDING_TIME, POSS_DUP_FLAG, REF_MSG_TYPE,
    REF_SEQ_NUM, RESET_SEQ_NUM_FLAG, SENDING_TIME, SESSION_REJECT_REASON, TEST_REQ_ID, TEXT,
};
use crate::time_util::now_utc_timestamp;

/// Build a message with the standard header (8/35/49/56/34/52).
fn base(config: &SessionConfig, msg_type: &str, seq: u64) -> Message {
    let mut m = Message::new();
    m.header.set(Field::string(8, &config.begin_string));
    m.header.set(Field::string(35, msg_type));
    m.header.set(Field::string(49, &config.sender_comp_id));
    m.header.set(Field::string(56, &config.target_comp_id));
    m.header.set(Field::int(34, seq as i64));
    m.header.set(Field::string(52, &now_utc_timestamp()));
    m
}

/// Logon (35=A) with EncryptMethod=0 and HeartBtInt; optional ResetSeqNumFlag and
/// NextExpectedMsgSeqNum (789).
pub(crate) fn logon(config: &SessionConfig, seq: u64, next_expected: Option<u64>) -> Message {
    let mut m = base(config, "A", seq);
    m.body.set(Field::int(ENCRYPT_METHOD, 0));
    m.body.set(Field::int(
        HEART_BT_INT,
        i64::from(config.heartbeat_interval),
    ));
    if config.reset_on_logon {
        m.body.set(Field::string(RESET_SEQ_NUM_FLAG, "Y"));
    }
    if let Some(n) = next_expected {
        m.body.set(Field::int(NEXT_EXPECTED_MSG_SEQ_NUM, n as i64));
    }
    m
}

/// Logout (35=5) with optional Text (58).
pub(crate) fn logout(config: &SessionConfig, seq: u64, text: Option<&str>) -> Message {
    let mut m = base(config, "5", seq);
    if let Some(t) = text {
        m.body.set(Field::string(TEXT, t));
    }
    m
}

/// Heartbeat (35=0), optionally echoing a TestReqID (112).
pub(crate) fn heartbeat(config: &SessionConfig, seq: u64, test_req_id: Option<&str>) -> Message {
    let mut m = base(config, "0", seq);
    if let Some(id) = test_req_id {
        m.body.set(Field::string(TEST_REQ_ID, id));
    }
    m
}

/// TestRequest (35=1) with a TestReqID (112).
pub(crate) fn test_request(config: &SessionConfig, seq: u64, id: &str) -> Message {
    let mut m = base(config, "1", seq);
    m.body.set(Field::string(TEST_REQ_ID, id));
    m
}

/// ResendRequest (35=2) for `[begin, end]` (end `0` means "to infinity").
pub(crate) fn resend_request(config: &SessionConfig, seq: u64, begin: u64, end: u64) -> Message {
    let mut m = base(config, "2", seq);
    m.body.set(Field::int(BEGIN_SEQ_NO, begin as i64));
    m.body.set(Field::int(END_SEQ_NO, end as i64));
    m
}

/// SequenceReset (35=4) with NewSeqNo (36); `gap_fill` sets GapFillFlag (123=Y) and PossDupFlag.
pub(crate) fn sequence_reset(
    config: &SessionConfig,
    seq: u64,
    new_seq_no: u64,
    gap_fill: bool,
) -> Message {
    let mut m = base(config, "4", seq);
    m.body.set(Field::int(NEW_SEQ_NO, new_seq_no as i64));
    if gap_fill {
        m.body.set(Field::string(GAP_FILL_FLAG, "Y"));
        m.header.set(Field::string(POSS_DUP_FLAG, "Y"));
    }
    m
}

/// Session-level Reject (35=3) referencing a sequence number with optional Text.
pub(crate) fn reject(config: &SessionConfig, seq: u64, ref_seq: u64, text: &str) -> Message {
    let mut m = base(config, "3", seq);
    m.body.set(Field::int(REF_SEQ_NUM, ref_seq as i64));
    m.body.set(Field::string(TEXT, text));
    m
}

/// Session-level Reject (35=3) with a SessionRejectReason (373).
pub(crate) fn reject_with_reason(
    config: &SessionConfig,
    seq: u64,
    ref_seq: u64,
    reason_code: u32,
    text: &str,
) -> Message {
    let mut m = base(config, "3", seq);
    m.body.set(Field::int(REF_SEQ_NUM, ref_seq as i64));
    m.body
        .set(Field::int(SESSION_REJECT_REASON, i64::from(reason_code)));
    m.body.set(Field::string(TEXT, text));
    m
}

/// Business Message Reject (35=j) with RefMsgType (372) and BusinessRejectReason (380).
pub(crate) fn business_message_reject(
    config: &SessionConfig,
    seq: u64,
    ref_seq: u64,
    ref_msg_type: Option<&str>,
    reason_code: u32,
    text: &str,
) -> Message {
    let mut m = base(config, "j", seq);
    m.body.set(Field::int(REF_SEQ_NUM, ref_seq as i64));
    if let Some(mt) = ref_msg_type {
        m.body.set(Field::string(REF_MSG_TYPE, mt));
    }
    m.body
        .set(Field::int(BUSINESS_REJECT_REASON, i64::from(reason_code)));
    m.body.set(Field::string(TEXT, text));
    m
}

/// Prepare a stored application message for resend: stamp PossDupFlag (43=Y) and OrigSendingTime
/// (122 = the original SendingTime), and refresh SendingTime (52).
pub(crate) fn prepare_resend(original: &Message) -> Message {
    let mut m = original.clone();
    let orig_sending = m
        .header
        .get(SENDING_TIME)
        .and_then(|f| f.as_str().ok())
        .map(str::to_owned);
    m.header.set(Field::string(POSS_DUP_FLAG, "Y"));
    if let Some(orig) = orig_sending {
        m.header.set(Field::string(ORIG_SENDING_TIME, &orig));
    }
    m.header
        .set(Field::string(SENDING_TIME, &now_utc_timestamp()));
    m
}

//! FIX tag numbers used by the session layer.

pub(crate) const MSG_SEQ_NUM: u32 = 34;
pub(crate) const POSS_DUP_FLAG: u32 = 43;
pub(crate) const SENDING_TIME: u32 = 52;
pub(crate) const ORIG_SENDING_TIME: u32 = 122;
pub(crate) const NEW_SEQ_NO: u32 = 36;
pub(crate) const GAP_FILL_FLAG: u32 = 123;
pub(crate) const BEGIN_SEQ_NO: u32 = 7;
pub(crate) const END_SEQ_NO: u32 = 16;
pub(crate) const RESET_SEQ_NUM_FLAG: u32 = 141;
pub(crate) const NEXT_EXPECTED_MSG_SEQ_NUM: u32 = 789;
pub(crate) const TEST_REQ_ID: u32 = 112;
pub(crate) const TEXT: u32 = 58;
pub(crate) const REF_SEQ_NUM: u32 = 45;
pub(crate) const REF_MSG_TYPE: u32 = 372;
pub(crate) const SESSION_REJECT_REASON: u32 = 373;
pub(crate) const BUSINESS_REJECT_REASON: u32 = 380;
pub(crate) const ENCRYPT_METHOD: u32 = 98;
pub(crate) const HEART_BT_INT: u32 = 108;

//! The integrator callback surface.

use truefix_core::Message;

use crate::session_id::SessionId;

/// Application callbacks invoked by the engine over a session's lifecycle.
///
/// All methods are async (FR-F7). Default implementations are no-ops so simple integrators
/// only override what they need. Inbound/outbound *admin* messages flow through
/// [`from_admin`](Application::from_admin) / [`to_admin`](Application::to_admin); application
/// messages through [`from_app`](Application::from_app) / [`to_app`](Application::to_app).
#[async_trait::async_trait]
pub trait Application: Send + Sync {
    /// Called once when a session is created.
    async fn on_create(&self, _session: &SessionId) {}

    /// Called when the session successfully logs on.
    async fn on_logon(&self, _session: &SessionId) {}

    /// Called when the session logs out or disconnects.
    async fn on_logout(&self, _session: &SessionId) {}

    /// Called before an outbound admin message is sent (allows mutation, e.g. credentials).
    async fn to_admin(&self, _message: &mut Message, _session: &SessionId) {}

    /// Called for an inbound admin message. Returning `Err` rejects the message
    /// (e.g. failed authentication on Logon).
    // `from_admin` is the established FIX callback name; it intentionally takes `&self`.
    #[allow(clippy::wrong_self_convention)]
    async fn from_admin(&self, _message: &Message, _session: &SessionId) -> Result<(), String> {
        Ok(())
    }

    /// Called before an outbound application message is sent.
    async fn to_app(&self, _message: &mut Message, _session: &SessionId) {}

    /// Called for an inbound application message.
    // `from_app` is the established FIX callback name; it intentionally takes `&self`.
    #[allow(clippy::wrong_self_convention)]
    async fn from_app(&self, _message: &Message, _session: &SessionId) -> Result<(), String> {
        Ok(())
    }
}

//! UTC SendingTime formatting.

use time::OffsetDateTime;

/// Format the current UTC time as a FIX UTCTimestamp `YYYYMMDD-HH:MM:SS.sss` (millisecond
/// precision). Never panics.
pub(crate) fn now_utc_timestamp() -> String {
    format_utc_timestamp(OffsetDateTime::now_utc())
}

fn format_utc_timestamp(dt: OffsetDateTime) -> String {
    let ms = dt.millisecond();
    format!(
        "{:04}{:02}{:02}-{:02}:{:02}:{:02}.{:03}",
        dt.year(),
        u8::from(dt.month()),
        dt.day(),
        dt.hour(),
        dt.minute(),
        dt.second(),
        ms
    )
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn format_has_expected_shape() {
        let s = now_utc_timestamp();
        // YYYYMMDD-HH:MM:SS.mmm => 21 chars
        assert_eq!(s.len(), 21, "{s}");
        assert_eq!(s.as_bytes().get(8), Some(&b'-'));
    }
}

//! Session identity.

use core::fmt;

/// Identifies a FIX session: BeginString + Sender/Target comp IDs (+ optional sub/location
/// IDs and a qualifier). Used to route connections and look up sessions.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct SessionId {
    /// BeginString, e.g. `"FIX.4.4"`.
    pub begin_string: String,
    /// SenderCompID (this engine's identity).
    pub sender_comp_id: String,
    /// Optional SenderSubID.
    pub sender_sub_id: Option<String>,
    /// Optional SenderLocationID.
    pub sender_location_id: Option<String>,
    /// TargetCompID (the counterparty).
    pub target_comp_id: String,
    /// Optional TargetSubID.
    pub target_sub_id: Option<String>,
    /// Optional TargetLocationID.
    pub target_location_id: Option<String>,
    /// Optional session qualifier (disambiguates multiple sessions with the same comp IDs).
    pub session_qualifier: Option<String>,
}

impl SessionId {
    /// Create a session id from the three required components.
    pub fn new(
        begin_string: impl Into<String>,
        sender_comp_id: impl Into<String>,
        target_comp_id: impl Into<String>,
    ) -> Self {
        Self {
            begin_string: begin_string.into(),
            sender_comp_id: sender_comp_id.into(),
            sender_sub_id: None,
            sender_location_id: None,
            target_comp_id: target_comp_id.into(),
            target_sub_id: None,
            target_location_id: None,
            session_qualifier: None,
        }
    }
}

impl fmt::Display for SessionId {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(
            f,
            "{}:{}->{}",
            self.begin_string, self.sender_comp_id, self.target_comp_id
        )?;
        if let Some(q) = &self.session_qualifier {
            write!(f, ":{q}")?;
        }
        Ok(())
    }
}

//! `truefix-transport` — tokio TCP Initiator and Acceptor that drive a [`Session`].
//!
//! Single- and multi-session initiator/acceptor over TCP or TLS (rustls), framing FIX messages off
//! the stream and pumping the sans-IO [`Session`] engine. Supports routing by SessionID, dynamic
//! sessions, allow-listing, reconnect, optional [`Services`] (persistent [`MessageStore`], [`Log`],
//! socket options, [`Monitor`]), and an operational monitoring surface.
//!
//! Design: `specs/001-fix-engine-parity/`.
#![cfg_attr(
    not(test),
    deny(
        clippy::unwrap_used,
        clippy::expect_used,
        clippy::panic,
        clippy::indexing_slicing
    )
)]

mod framing;

use std::collections::HashMap;
use std::future::pending;
use std::net::{IpAddr, SocketAddr};
use std::sync::atomic::{AtomicBool, Ordering};
use std::sync::{Arc, Mutex};
use std::time::Duration;

use tokio::io::{self, AsyncRead, AsyncReadExt, AsyncWrite, AsyncWriteExt};
use tokio::net::{TcpListener, TcpStream};
use tokio::sync::mpsc;
use tokio::task::JoinHandle;
use tokio::time::{interval, MissedTickBehavior};

use truefix_core::{decode, Message};
use truefix_log::Log;
use truefix_session::{
    Action, Application, Event, Session, SessionConfig, SessionId, SessionState, SessionStatus,
};
use truefix_store::MessageStore;

use framing::frame_length;

/// TCP socket options applied to each connection.
#[derive(Debug, Clone, Copy)]
pub struct SocketOptions {
    /// Disable Nagle's algorithm (TCP_NODELAY).
    pub tcp_no_delay: bool,
}

impl Default for SocketOptions {
    fn default() -> Self {
        Self { tcp_no_delay: true }
    }
}

impl SocketOptions {
    /// Apply the options to a connected stream (best-effort).
    pub fn apply(&self, stream: &TcpStream) {
        let _ = stream.set_nodelay(self.tcp_no_delay);
    }
}

/// Optional per-session services: a persistent message store, a log, and socket options.
#[derive(Clone, Default)]
pub struct Services {
    /// Persistent store for sequence-number continuity (and future cross-restart resend).
    pub store: Option<Arc<dyn MessageStore>>,
    /// Message/event log.
    pub log: Option<Arc<dyn Log>>,
    /// TCP socket options.
    pub socket_options: SocketOptions,
    /// Operational monitor.
    pub monitor: Option<Monitor>,
}

/// Control messages to a running session task.
enum Control {
    /// Begin a graceful logout.
    Logout,
    /// Operationally reset the session's sequence numbers and store.
    Reset,
}

/// Operational monitoring (FR-L): live session status plus reset / force-logout actions
/// (the JMX-equivalent surface).
#[derive(Clone, Default)]
pub struct Monitor {
    inner: Arc<Mutex<HashMap<SessionId, MonitorEntry>>>,
}

struct MonitorEntry {
    status: SessionStatus,
    connected: bool,
    control: mpsc::Sender<Control>,
}

impl Monitor {
    /// Create an empty monitor.
    pub fn new() -> Self {
        Self::default()
    }

    fn register(&self, id: SessionId, status: SessionStatus, control: mpsc::Sender<Control>) {
        if let Ok(mut map) = self.inner.lock() {
            map.insert(
                id,
                MonitorEntry {
                    status,
                    connected: true,
                    control,
                },
            );
        }
    }

    fn update(&self, id: &SessionId, status: SessionStatus) {
        if let Ok(mut map) = self.inner.lock() {
            if let Some(entry) = map.get_mut(id) {
                entry.status = status;
            }
        }
    }

    fn mark_disconnected(&self, id: &SessionId) {
        if let Ok(mut map) = self.inner.lock() {
            if let Some(entry) = map.get_mut(id) {
                entry.connected = false;
            }
        }
    }

    /// The latest status snapshot for `id`.
    pub fn status(&self, id: &SessionId) -> Option<SessionStatus> {
        self.inner.lock().ok()?.get(id).map(|e| e.status)
    }

    /// Whether `id`'s connection is currently up.
    pub fn is_connected(&self, id: &SessionId) -> bool {
        self.inner
            .lock()
            .ok()
            .and_then(|m| m.get(id).map(|e| e.connected))
            .unwrap_or(false)
    }

    /// All known session ids.
    pub fn sessions(&self) -> Vec<SessionId> {
        self.inner
            .lock()
            .map(|m| m.keys().cloned().collect())
            .unwrap_or_default()
    }

    fn control_for(&self, id: &SessionId) -> Option<mpsc::Sender<Control>> {
        self.inner.lock().ok()?.get(id).map(|e| e.control.clone())
    }

    /// Request a graceful logout of `id`.
    pub async fn force_logout(&self, id: &SessionId) -> bool {
        match self.control_for(id) {
            Some(c) => c.send(Control::Logout).await.is_ok(),
            None => false,
        }
    }

    /// Request an operational sequence reset of `id`.
    pub async fn reset(&self, id: &SessionId) -> bool {
        match self.control_for(id) {
            Some(c) => c.send(Control::Reset).await.is_ok(),
            None => false,
        }
    }
}

/// A handle to a running session task.
pub struct SessionHandle {
    control: mpsc::Sender<Control>,
    task: JoinHandle<()>,
}

impl SessionHandle {
    /// Request a graceful logout.
    pub async fn logout(&self) {
        let _ = self.control.send(Control::Logout).await;
    }

    /// Wait for the session task to finish.
    pub async fn join(self) {
        let _ = self.task.await;
    }
}

/// Connect out as an initiator and run the session.
pub async fn connect_initiator<A>(
    addr: SocketAddr,
    config: SessionConfig,
    app: Arc<A>,
) -> io::Result<SessionHandle>
where
    A: Application + 'static,
{
    connect_initiator_with(addr, config, app, Services::default()).await
}

/// Connect out as an initiator with persistent store/log services.
pub async fn connect_initiator_with<A>(
    addr: SocketAddr,
    config: SessionConfig,
    app: Arc<A>,
    services: Services,
) -> io::Result<SessionHandle>
where
    A: Application + 'static,
{
    let stream = TcpStream::connect(addr).await?;
    Ok(spawn_session(stream, config, app, services))
}

/// Connect out as an initiator over TLS (FR-F6).
///
/// `server_name` is the SNI/host name presented to the server (e.g. `"example.com"`).
pub async fn connect_initiator_tls<A>(
    addr: SocketAddr,
    config: SessionConfig,
    app: Arc<A>,
    services: Services,
    tls: Arc<rustls::ClientConfig>,
    server_name: rustls::pki_types::ServerName<'static>,
) -> io::Result<SessionHandle>
where
    A: Application + 'static,
{
    let tcp = TcpStream::connect(addr).await?;
    services.socket_options.apply(&tcp);
    let connector = tokio_rustls::TlsConnector::from(tls);
    let stream = connector.connect(server_name, tcp).await?;
    Ok(spawn_session_io(stream, config, app, services))
}

/// A listening acceptor that serves one static session configuration per connection.
pub struct Acceptor<A: Application + 'static> {
    listener: TcpListener,
    config: SessionConfig,
    app: Arc<A>,
    services: Services,
}

impl<A: Application + 'static> Acceptor<A> {
    /// Bind to `addr`.
    pub async fn bind(addr: SocketAddr, config: SessionConfig, app: Arc<A>) -> io::Result<Self> {
        Self::bind_with(addr, config, app, Services::default()).await
    }

    /// Bind to `addr` with persistent store/log services.
    pub async fn bind_with(
        addr: SocketAddr,
        config: SessionConfig,
        app: Arc<A>,
        services: Services,
    ) -> io::Result<Self> {
        let listener = TcpListener::bind(addr).await?;
        Ok(Self {
            listener,
            config,
            app,
            services,
        })
    }

    /// The bound local address (useful when binding to port 0).
    pub fn local_addr(&self) -> io::Result<SocketAddr> {
        self.listener.local_addr()
    }

    /// Spawn the accept loop. Each connection is served as a session.
    pub fn serve(self) -> JoinHandle<()> {
        tokio::spawn(async move {
            while let Ok((stream, _peer)) = self.listener.accept().await {
                let _ = spawn_session(
                    stream,
                    self.config.clone(),
                    self.app.clone(),
                    self.services.clone(),
                );
            }
        })
    }
}

fn spawn_session<A>(
    stream: TcpStream,
    config: SessionConfig,
    app: Arc<A>,
    services: Services,
) -> SessionHandle
where
    A: Application + 'static,
{
    services.socket_options.apply(&stream);
    spawn_session_io(stream, config, app, services)
}

fn spawn_session_io<A, S>(
    stream: S,
    config: SessionConfig,
    app: Arc<A>,
    services: Services,
) -> SessionHandle
where
    A: Application + 'static,
    S: AsyncRead + AsyncWrite + Unpin + Send + 'static,
{
    let (control_tx, control_rx) = mpsc::channel(8);
    let task = {
        let control_tx = control_tx.clone();
        tokio::spawn(async move {
            run_connection(
                stream,
                config,
                app,
                services,
                control_tx,
                control_rx,
                Vec::new(),
            )
            .await;
        })
    };
    SessionHandle {
        control: control_tx,
        task,
    }
}

#[allow(clippy::too_many_arguments)]
async fn run_connection<A, S>(
    mut stream: S,
    config: SessionConfig,
    app: Arc<A>,
    services: Services,
    control_tx: mpsc::Sender<Control>,
    mut control: mpsc::Receiver<Control>,
    mut buf: Vec<u8>,
) where
    A: Application + 'static,
    S: AsyncRead + AsyncWrite + Unpin,
{
    let mut session = Session::new(config);
    let id = session.id().clone();
    app.on_create(&id).await;

    // Restore sequence numbers from the store (continuity across restarts).
    if let Some(store) = &services.store {
        let out = store.next_sender_seq().await.unwrap_or(1);
        let inn = store.next_target_seq().await.unwrap_or(1);
        session.seed_sequences(out, inn);
    }

    if let Some(monitor) = &services.monitor {
        monitor.register(id.clone(), session.status(), control_tx);
    }

    let mut chunk = [0u8; 4096];
    let mut ticker = interval(Duration::from_secs(1));
    ticker.set_missed_tick_behavior(MissedTickBehavior::Delay);

    let mut logged_on = false;
    let mut control_open = true;
    let mut closing = false;

    if dispatch(
        &mut session,
        Event::Connected,
        &mut stream,
        &app,
        &id,
        &services,
        &mut logged_on,
    )
    .await
    .is_err()
    {
        closing = true;
    }

    // Drain any bytes pre-read while routing the connection (acceptor: the inbound Logon).
    if !closing
        && !buf.is_empty()
        && drain_messages(
            &mut buf,
            &mut session,
            &mut stream,
            &app,
            &id,
            &services,
            &mut logged_on,
        )
        .await
        .is_err()
    {
        closing = true;
    }

    while !closing {
        tokio::select! {
            read = stream.read(&mut chunk) => match read {
                Ok(0) | Err(_) => break,
                Ok(n) => {
                    if let Some(slice) = chunk.get(..n) {
                        buf.extend_from_slice(slice);
                    }
                    if drain_messages(&mut buf, &mut session, &mut stream, &app, &id, &services, &mut logged_on)
                        .await
                        .is_err()
                    {
                        closing = true;
                    }
                }
            },
            _ = ticker.tick() => {
                if dispatch(&mut session, Event::Tick, &mut stream, &app, &id, &services, &mut logged_on)
                    .await
                    .is_err()
                {
                    closing = true;
                }
            },
            ctrl = recv_control(&mut control, control_open) => match ctrl {
                Some(Control::Logout) => {
                    if dispatch(&mut session, Event::StartLogout, &mut stream, &app, &id, &services, &mut logged_on)
                        .await
                        .is_err()
                    {
                        closing = true;
                    }
                }
                Some(Control::Reset) => {
                    session.reset();
                    if let Some(store) = &services.store {
                        let _ = store.reset().await;
                    }
                    if let Some(monitor) = &services.monitor {
                        monitor.update(&id, session.status());
                    }
                }
                None => control_open = false,
            },
        }
    }

    let _ = stream.shutdown().await;
    if let Some(monitor) = &services.monitor {
        monitor.mark_disconnected(&id);
    }
    if logged_on {
        app.on_logout(&id).await;
        if let Some(log) = &services.log {
            log.on_event(&format!("{id}: logout"));
        }
    }
}

/// Await a control message, or never resolve once the channel is closed (avoids a busy loop).
async fn recv_control(control: &mut mpsc::Receiver<Control>, open: bool) -> Option<Control> {
    if open {
        control.recv().await
    } else {
        pending::<Option<Control>>().await
    }
}

#[allow(clippy::too_many_arguments)]
async fn drain_messages<A, S>(
    buf: &mut Vec<u8>,
    session: &mut Session,
    stream: &mut S,
    app: &Arc<A>,
    id: &SessionId,
    services: &Services,
    logged_on: &mut bool,
) -> Result<(), ()>
where
    A: Application + 'static,
    S: AsyncRead + AsyncWrite + Unpin,
{
    loop {
        match frame_length(buf) {
            Ok(Some(total)) => {
                let raw: Vec<u8> = buf.drain(..total).collect();
                if let Ok(msg) = decode(&raw) {
                    if let Some(log) = &services.log {
                        log.on_incoming(&String::from_utf8_lossy(&raw));
                    }
                    // Authentication / admin acceptance: an admin message the application rejects
                    // (e.g. a Logon with bad credentials) tears the session down without a response.
                    if is_admin(&msg) {
                        if app.from_admin(&msg, id).await.is_err() {
                            if let Some(log) = &services.log {
                                log.on_event(&format!(
                                    "{id}: admin message rejected by application"
                                ));
                            }
                            return Err(());
                        }
                    } else {
                        // Business rejects are produced by the dictionary hook; deliver regardless.
                        let _ = app.from_app(&msg, id).await;
                    }
                    dispatch(
                        session,
                        Event::Received(msg),
                        stream,
                        app,
                        id,
                        services,
                        logged_on,
                    )
                    .await?;
                }
                // Garbled frames are dropped at this stage; RejectGarbledMessage arrives in S3.
            }
            Ok(None) => return Ok(()),
            Err(_) => {
                buf.clear();
                return Ok(());
            }
        }
    }
}

/// Run the engine for one event and perform the resulting actions. Returns `Err` if the
/// session should be torn down.
#[allow(clippy::too_many_arguments)]
async fn dispatch<A, S>(
    session: &mut Session,
    event: Event,
    stream: &mut S,
    app: &Arc<A>,
    id: &SessionId,
    services: &Services,
    logged_on: &mut bool,
) -> Result<(), ()>
where
    A: Application + 'static,
    S: AsyncWrite + Unpin,
{
    let actions = session.handle(event);

    if !*logged_on && session.is_logged_on() {
        *logged_on = true;
        app.on_logon(id).await;
        if let Some(log) = &services.log {
            log.on_event(&format!("{id}: logon"));
        }
    }

    let mut disconnect = false;
    for action in actions {
        match action {
            Action::Send(mut msg) => {
                if is_admin(&msg) {
                    app.to_admin(&mut msg, id).await;
                } else {
                    app.to_app(&mut msg, id).await;
                }
                let bytes = msg.encode();
                if let Some(log) = &services.log {
                    log.on_outgoing(&String::from_utf8_lossy(&bytes));
                }
                if stream.write_all(&bytes).await.is_err() {
                    return Err(());
                }
            }
            Action::Disconnect => disconnect = true,
        }
    }
    let _ = stream.flush().await;

    // Persist sequence numbers for restart continuity (best-effort).
    if let Some(store) = &services.store {
        let _ = store.set_next_sender_seq(session.next_out_seq()).await;
        let _ = store.set_next_target_seq(session.next_in_seq()).await;
    }

    if let Some(monitor) = &services.monitor {
        monitor.update(id, session.status());
    }

    if disconnect || session.state() == SessionState::Disconnected {
        Err(())
    } else {
        Ok(())
    }
}

fn is_admin(msg: &Message) -> bool {
    matches!(
        msg.msg_type(),
        Some("0" | "1" | "2" | "3" | "4" | "5" | "A")
    )
}

// ===========================================================================================
// Multi-session acceptor (routing by SessionID), dynamic sessions, and allow-listing (S6).
// ===========================================================================================

struct Registry {
    sessions: HashMap<SessionId, SessionConfig>,
    template: Option<SessionConfig>,
    allowed_remotes: Option<Vec<IpAddr>>,
}

/// Builds and serves a multi-session acceptor with optional dynamic sessions and allow-listing.
pub struct AcceptorBuilder<A: Application + 'static> {
    listener: TcpListener,
    app: Arc<A>,
    sessions: HashMap<SessionId, SessionConfig>,
    template: Option<SessionConfig>,
    allowed_remotes: Option<Vec<IpAddr>>,
    services: Services,
    tls: Option<Arc<rustls::ServerConfig>>,
}

impl<A: Application + 'static> AcceptorBuilder<A> {
    /// Bind a multi-session acceptor.
    pub async fn bind(addr: SocketAddr, app: Arc<A>) -> io::Result<Self> {
        let listener = TcpListener::bind(addr).await?;
        Ok(Self {
            listener,
            app,
            sessions: HashMap::new(),
            template: None,
            allowed_remotes: None,
            services: Services::default(),
            tls: None,
        })
    }

    /// Terminate TLS on each accepted connection using `config` (FR-F6).
    #[must_use]
    pub fn with_tls(mut self, config: Arc<rustls::ServerConfig>) -> Self {
        self.tls = Some(config);
        self
    }

    /// The bound local address.
    pub fn local_addr(&self) -> io::Result<SocketAddr> {
        self.listener.local_addr()
    }

    /// Register a static session (keyed by its SessionID).
    #[must_use]
    pub fn with_session(mut self, config: SessionConfig) -> Self {
        self.sessions.insert(config.session_id(), config);
        self
    }

    /// Set a dynamic-session template: connections that don't match a static session are accepted
    /// using this template (AcceptorTemplate / DynamicSession).
    #[must_use]
    pub fn with_dynamic_template(mut self, template: SessionConfig) -> Self {
        self.template = Some(template);
        self
    }

    /// Only accept connections from these remote IP addresses (AllowedRemoteAddresses).
    #[must_use]
    pub fn allow_remotes(mut self, ips: Vec<IpAddr>) -> Self {
        self.allowed_remotes = Some(ips);
        self
    }

    /// Attach store/log/socket services.
    #[must_use]
    pub fn with_services(mut self, services: Services) -> Self {
        self.services = services;
        self
    }

    /// Spawn the accept loop.
    pub fn serve(self) -> JoinHandle<()> {
        let registry = Arc::new(Registry {
            sessions: self.sessions,
            template: self.template,
            allowed_remotes: self.allowed_remotes,
        });
        let app = self.app;
        let services = self.services;
        let listener = self.listener;
        let tls = self.tls.map(tokio_rustls::TlsAcceptor::from);
        tokio::spawn(async move {
            while let Ok((stream, peer)) = listener.accept().await {
                if let Some(allowed) = &registry.allowed_remotes {
                    if !allowed.contains(&peer.ip()) {
                        continue; // refuse: not in the allow-list
                    }
                }
                services.socket_options.apply(&stream);
                let registry = registry.clone();
                let app = app.clone();
                let services = services.clone();
                match &tls {
                    Some(acceptor) => {
                        let acceptor = acceptor.clone();
                        tokio::spawn(async move {
                            if let Ok(tls_stream) = acceptor.accept(stream).await {
                                route_and_run(tls_stream, app, registry, services).await;
                            }
                        });
                    }
                    None => {
                        tokio::spawn(async move {
                            route_and_run(stream, app, registry, services).await;
                        });
                    }
                }
            }
        })
    }
}

async fn route_and_run<A, S>(
    mut stream: S,
    app: Arc<A>,
    registry: Arc<Registry>,
    services: Services,
) where
    A: Application + 'static,
    S: AsyncRead + AsyncWrite + Unpin + Send + 'static,
{
    // Read until the first complete message (the Logon) so we can route by SessionID.
    let mut buf: Vec<u8> = Vec::new();
    let mut chunk = [0u8; 4096];
    let logon = loop {
        match stream.read(&mut chunk).await {
            Ok(0) | Err(_) => return,
            Ok(n) => {
                if let Some(slice) = chunk.get(..n) {
                    buf.extend_from_slice(slice);
                }
            }
        }
        match frame_length(&buf) {
            Ok(Some(total)) => match buf.get(..total).map(decode) {
                Some(Ok(msg)) => break msg,
                _ => return,
            },
            Ok(None) => continue,
            Err(_) => return,
        }
    };

    let begin = logon.begin_string().unwrap_or_default().to_owned();
    let their_sender = field_str(&logon, 49);
    let their_target = field_str(&logon, 56);
    // Our SessionID reverses the counterparty's comp IDs.
    let sid = SessionId::new(begin.clone(), their_target.clone(), their_sender.clone());

    let config = registry.sessions.get(&sid).cloned().or_else(|| {
        registry
            .template
            .as_ref()
            .map(|t| dynamic_config(t, &begin, &their_target, &their_sender))
    });
    let Some(config) = config else {
        return; // no static match and no template -> refuse
    };

    let (control_tx, control_rx) = mpsc::channel(8);
    run_connection(stream, config, app, services, control_tx, control_rx, buf).await;
}

fn field_str(msg: &Message, tag: u32) -> String {
    msg.header
        .get(tag)
        .and_then(|f| f.as_str().ok())
        .unwrap_or_default()
        .to_owned()
}

fn dynamic_config(
    template: &SessionConfig,
    begin: &str,
    our_sender: &str,
    our_target: &str,
) -> SessionConfig {
    let mut config = template.clone();
    config.begin_string = begin.to_owned();
    config.sender_comp_id = our_sender.to_owned();
    config.target_comp_id = our_target.to_owned();
    config
}

// ===========================================================================================
// Reconnecting initiator (S6).
// ===========================================================================================

/// Handle to a reconnecting initiator loop.
pub struct ReconnectHandle {
    stop: Arc<AtomicBool>,
    task: JoinHandle<()>,
}

impl ReconnectHandle {
    /// Signal the loop to stop after the current attempt.
    pub fn stop(&self) {
        self.stop.store(true, Ordering::SeqCst);
    }

    /// Wait for the loop to finish.
    pub async fn join(self) {
        let _ = self.task.await;
    }
}

/// Connect out as an initiator, automatically reconnecting after `config.reconnect_interval`
/// seconds whenever the connection drops, until stopped.
pub fn connect_initiator_reconnecting<A>(
    addr: SocketAddr,
    config: SessionConfig,
    app: Arc<A>,
    services: Services,
) -> ReconnectHandle
where
    A: Application + 'static,
{
    let stop = Arc::new(AtomicBool::new(false));
    let loop_stop = stop.clone();
    let interval = Duration::from_secs(u64::from(config.reconnect_interval).max(1));
    let task = tokio::spawn(async move {
        while !loop_stop.load(Ordering::SeqCst) {
            if let Ok(stream) = TcpStream::connect(addr).await {
                let (control_tx, control_rx) = mpsc::channel(8);
                run_connection(
                    stream,
                    config.clone(),
                    app.clone(),
                    services.clone(),
                    control_tx,
                    control_rx,
                    Vec::new(),
                )
                .await;
            }
            if loop_stop.load(Ordering::SeqCst) {
                break;
            }
            tokio::time::sleep(interval).await;
        }
    });
    ReconnectHandle { stop, task }
}

//! Extract complete FIX messages from a byte stream.

use truefix_core::DecodeError;

const SOH: u8 = 0x01;

/// If `buf` begins with at least one complete FIX message, return `Ok(Some(total_len))` (the
/// byte length of that message). Return `Ok(None)` if more bytes are needed, or `Err` if the
/// start of the buffer cannot be framed.
///
/// Uses BodyLength (tag 9) to locate the body, then accounts for the fixed 7-byte
/// `10=XXX<SOH>` CheckSum trailer.
pub(crate) fn frame_length(buf: &[u8]) -> Result<Option<usize>, DecodeError> {
    let Some(soh1) = find(buf, SOH) else {
        return Ok(None);
    };
    if buf.get(0..2) != Some(b"8=") {
        return Err(DecodeError::MissingBeginString);
    }

    let after8 = buf.get(soh1 + 1..).unwrap_or(&[]);
    let Some(soh2_rel) = find(after8, SOH) else {
        return Ok(None);
    };
    let bl_field = after8.get(..soh2_rel).unwrap_or(&[]);
    if bl_field.get(0..2) != Some(b"9=") {
        return Err(DecodeError::InvalidBodyLength);
    }
    let bl_val = bl_field.get(2..).unwrap_or(&[]);
    let body_len: usize = core::str::from_utf8(bl_val)
        .ok()
        .and_then(|s| s.parse().ok())
        .ok_or(DecodeError::InvalidBodyLength)?;

    let body_start = soh1 + 1 + soh2_rel + 1;
    // CheckSum field "10=" + 3 digits + SOH is always 7 bytes.
    let total = body_start + body_len + 7;
    if buf.len() >= total {
        Ok(Some(total))
    } else {
        Ok(None)
    }
}

fn find(haystack: &[u8], needle: u8) -> Option<usize> {
    haystack.iter().position(|&b| b == needle)
}

#[cfg(test)]
mod tests {
    use super::*;

    const MSG: &[u8] = b"8=FIX.4.4\x019=21\x0135=A\x0195=7\x0196=rawdata\x0110=086\x01";

    #[test]
    fn frames_complete_message() {
        assert_eq!(frame_length(MSG), Ok(Some(MSG.len())));
    }

    #[test]
