//! T010 — round-trip + byte-exact BodyLength/CheckSum.
//!
//! `V_RAW` is a known-good wire vector (FIX-spec-determined data, BodyLength 21, CheckSum 086)
//! used as an external anchor. The QuickFIX/J cross-vectors (T099) are a later supplement.

use truefix_core::{decode, encode, Field, Message};

const V_RAW: &[u8] = b"8=FIX.4.4\x019=21\x0135=A\x0195=7\x0196=rawdata\x0110=086\x01";

#[test]
fn decodes_known_rawdata_vector() {
    let m = decode(V_RAW).unwrap();
    assert_eq!(m.begin_string(), Some("FIX.4.4"));
    assert_eq!(m.msg_type(), Some("A"));
    // length-prefixed binary data field preserved exactly
    assert_eq!(m.body.get(96).unwrap().value_bytes(), b"rawdata");
}

#[test]
fn rawdata_vector_roundtrips_byte_identical() {
    let m = decode(V_RAW).unwrap();
    assert_eq!(encode(&m), V_RAW);
}

#[test]
fn bodylength_and_checksum_recomputed_correctly() {
    let m = decode(V_RAW).unwrap();
    let s = String::from_utf8(encode(&m)).unwrap();
    assert!(s.contains("9=21\u{1}"), "{s:?}");
    assert!(s.ends_with("10=086\u{1}"), "{s:?}");
}

#[test]
fn programmatic_newordersingle_roundtrips() {
    let mut m = Message::new();
    m.header.set(Field::string(8, "FIX.4.2"));
    m.header.set(Field::string(35, "D"));
    m.header.set(Field::int(34, 1));
    m.header.set(Field::string(49, "SENDER"));
    m.header.set(Field::string(56, "TARGET"));
    m.header.set(Field::string(52, "20240101-12:00:00"));
    m.body.set(Field::string(11, "ORDER1"));
    m.body.set(Field::string(55, "AAPL"));
    m.body.set(Field::int(54, 1));
    m.body.set(Field::int(38, 100));
    m.body.set(Field::string(40, "2"));
    m.body.set(Field::string(44, "150.25"));

    let bytes = encode(&m);
    let decoded = decode(&bytes).unwrap();

    // encode->decode->encode is byte-stable
    assert_eq!(encode(&decoded), bytes);
    // typed access survives the round-trip
    assert_eq!(decoded.body.get(55).unwrap().as_str().unwrap(), "AAPL");
    assert_eq!(
        decoded
            .body
            .get(44)
            .unwrap()
            .as_decimal()
            .unwrap()
            .to_string(),
        "150.25"
    );
    // header was classified correctly
    assert_eq!(decoded.header.get(49).unwrap().as_str().unwrap(), "SENDER");
}

//! T009 — table-driven field type / converter tests.

use truefix_core::Field;

#[test]
fn typed_conversions_succeed() {
    let cases_int = [(38u32, "100", 100i64), (34, "1", 1), (34, "-5", -5)];
    for (tag, raw, want) in cases_int {
        assert_eq!(Field::string(tag, raw).as_int().unwrap(), want, "tag {tag}");
    }

    assert_eq!(
        Field::string(44, "150.25")
            .as_decimal()
            .unwrap()
            .to_string(),
        "150.25"
    );
    assert_eq!(Field::string(35, "D").as_char().unwrap(), 'D');
    assert!(Field::string(43, "Y").as_bool().unwrap());
    assert!(!Field::string(43, "N").as_bool().unwrap());
    assert_eq!(Field::string(55, "AAPL").as_str().unwrap(), "AAPL");
    assert_eq!(Field::int(38, 100).value_bytes(), b"100");
}

#[test]
fn bad_conversions_error_never_panic() {
    assert!(Field::string(38, "x").as_int().is_err());
    assert!(Field::string(44, "x").as_decimal().is_err());
    assert!(Field::string(35, "AB").as_char().is_err());
    assert!(Field::string(35, "").as_char().is_err());
    assert!(Field::string(43, "Maybe").as_bool().is_err());
}

#[test]
fn utc_timestamp_nanosecond_and_picosecond_truncation() {
    let with_ms = Field::string(52, "20120331-10:15:30.444")
        .as_utc_timestamp()
        .unwrap();
    assert_eq!(with_ms.year(), 2012);
    assert_eq!(with_ms.nanosecond(), 444_000_000);

    // Picosecond input accepted, stored truncated to nanosecond (FR-B7).
    let with_ps = Field::string(52, "20120331-10:15:30.123456789012")
        .as_utc_timestamp()
        .unwrap();
    assert_eq!(with_ps.nanosecond(), 123_456_789);

    let no_frac = Field::string(52, "20120331-10:15:30")
        .as_utc_timestamp()
        .unwrap();
    assert_eq!(no_frac.nanosecond(), 0);
}

#[test]
fn invalid_timestamp_errors() {
    assert!(Field::string(52, "not-a-time").as_utc_timestamp().is_err());
    assert!(Field::string(52, "20121331-10:15:30") // month 13
        .as_utc_timestamp()
        .is_err());
    assert!(Field::string(52, "20120331-25:00:00") // hour 25
        .as_utc_timestamp()
        .is_err());
}

//! T012 — repeating-group model + encode (dictionary-driven group *parsing* is Stage S4).

use truefix_core::{decode, encode, Field, FieldMap, Group, Message};

#[test]
fn build_group_encodes_to_known_vector() {
    // Known-good wire vector (FIX-spec data): NoPartyIDs=1, BodyLength 35, CheckSum 040.
    let expected: &[u8] =
        b"8=FIX.4.4\x019=35\x0135=D\x01453=1\x01448=PARTY_1\x01447=I\x01452=6\x0110=040\x01";

    let mut msg = Message::new();
    msg.header.set(Field::string(8, "FIX.4.4"));
    msg.header.set(Field::string(35, "D"));

    let mut entry = FieldMap::new();
    entry.add_field(Field::string(448, "PARTY_1"));
    entry.add_field(Field::string(447, "I"));
    entry.add_field(Field::int(452, 6));
    let mut group = Group::new(453);
    group.add_entry(entry);
    msg.body.add_group(group);

    assert_eq!(encode(&msg), expected);
}

#[test]
fn empty_group_renders_zero_count() {
    let mut msg = Message::new();
    msg.header.set(Field::string(8, "FIX.4.2"));
    msg.header.set(Field::string(35, "D"));
    msg.body.add_group(Group::new(453));

    let s = String::from_utf8(encode(&msg)).unwrap();
    assert!(s.contains("453=0\u{1}"), "{s:?}");
}

#[test]
fn nested_group_roundtrips_at_byte_level() {
    // Build a group whose entry contains a nested group, encode it, then confirm a flat
    // decode re-encodes to identical bytes (group-aware decode arrives in S4).
    let mut nested_entry = FieldMap::new();
    nested_entry.add_field(Field::string(524, "SUBPARTY"));
    let mut nested = Group::new(523);
    nested.add_entry(nested_entry);

    let mut outer_entry = FieldMap::new();
    outer_entry.add_field(Field::string(448, "P1"));
    outer_entry.add_field(Field::string(447, "I"));
    outer_entry.add_group(nested);
    let mut outer = Group::new(453);
    outer.add_entry(outer_entry);

    let mut msg = Message::new();
    msg.header.set(Field::string(8, "FIX.4.4"));
    msg.header.set(Field::string(35, "D"));
    msg.body.add_group(outer);

    let bytes = encode(&msg);
    let decoded = decode(&bytes).unwrap();
    assert_eq!(encode(&decoded), bytes);
}

